namespace sv_e3745e66beba4546a2524846940ba10c;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

public class ThemeInfo
{
    public ThemeMode Mode { get; set; } = ThemeMode.Light;
    public string AccentColor { get; set; } = "#0d6efd";
}

@using Microsoft.AspNetCore.Components

<span class="theme-indicator" style="color: @Theme?.AccentColor;">
    @GetThemeIcon() @Theme?.Mode
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private string GetThemeIcon() => Theme?.Mode switch
    {
        ThemeMode.Dark => "🌙",
        ThemeMode.System => "💻",
        _ => "☀️"
    };
}

@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label">Theme</label>
    <div class="btn-group" role="group">
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            var isActive = mode == Theme?.Mode;
            <button class="btn @(isActive ? "btn-primary" : "btn-outline-primary")"
                    @onclick="() => SetTheme(mode)">
                @mode
            </button>
        }
    </div>
</div>

<div class="mb-3">
    <label class="form-label">Accent Color</label>
    <input type="color"
           class="form-control form-control-color"
           value="@(Theme?.AccentColor ?? "#0d6efd")"
           @onchange="SetAccentColor" />
</div>

<div class="mt-4 p-3 border rounded" style="border-color: @Theme?.AccentColor !important;">
    <strong>Preview:</strong>
    Current theme is <strong>@Theme?.Mode</strong> with accent
    <span style="color: @Theme?.AccentColor;">@Theme?.AccentColor</span>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private async Task SetTheme(ThemeMode mode)
    {
        var updated = new ThemeInfo
        {
            Mode = mode,
            AccentColor = Theme?.AccentColor ?? "#0d6efd"
        };
        await ThemeSource.NotifyChangedAsync(updated);
    }

    private async Task SetAccentColor(ChangeEventArgs e)
    {
        var updated = new ThemeInfo
        {
            Mode = Theme?.Mode ?? ThemeMode.Light,
            AccentColor = e.Value?.ToString() ?? "#0d6efd"
        };
        await ThemeSource.NotifyChangedAsync(updated);
    }
}

